// --- SocialLoginManager.kt ---

import android.content.Context
import android.content.Intent
import android.util.Log
import androidx.activity.result.ActivityResultLauncher
import androidx.activity.result.IntentSenderRequest
import androidx.activity.result.contract.ActivityResultContracts
import androidx.appcompat.app.AppCompatActivity
import com.facebook.CallbackManager
import com.facebook.FacebookCallback
import com.facebook.FacebookException
import com.facebook.login.LoginManager
import com.facebook.login.LoginResult
import com.google.android.gms.auth.api.identity.BeginSignInRequest
import com.google.android.gms.auth.api.identity.Identity
import com.google.android.gms.auth.api.identity.SignInClient

data class SocialLoginResult(
    val provider: SocialProvider,
    val token: String,
    val userId: String?,
    val email: String?,
    val displayName: String?
)

enum class SocialProvider {
    FACEBOOK, GOOGLE
}

sealed class SocialLoginError {
    data class AuthFailed(val message: String) : SocialLoginError()
    data class Cancelled(val message: String = "Login cancelled") : SocialLoginError()
    data class ConfigError(val message: String) : SocialLoginError()
}

interface SocialLoginCallback {
    fun onSuccess(result: SocialLoginResult)
    fun onError(error: SocialLoginError)
}

class SocialLoginManager private constructor(
    private val activity: AppCompatActivity,
    private val config: SocialLoginConfig,
    private val callback: SocialLoginCallback
) {

    // --- Configuration loaded from secure sources, NOT hardcoded ---
    data class SocialLoginConfig(
        val googleClientId: String,
        val facebookAppId: String
    ) {
        init {
            require(googleClientId.isNotBlank()) { "Google Client ID must not be blank" }
            require(facebookAppId.isNotBlank()) { "Facebook App ID must not be blank" }
            // Validate that nobody accidentally hardcoded secrets
            require(!googleClientId.contains("secret", ignoreCase = true)) {
                "Do not include secrets in client-side config"
            }
        }

        companion object {
            /**
             * Load config from BuildConfig fields populated by secrets-gradle-plugin
             * from local.properties (gitignored) or CI environment variables.
             */
            fun fromBuildConfig(): SocialLoginConfig {
                return SocialLoginConfig(
                    googleClientId = BuildConfig.GOOGLE_CLIENT_ID,
                    facebookAppId = BuildConfig.FACEBOOK_APP_ID
                )
            }

            /**
             * Load config from Android resource strings (set via CI/CD or local config).
             */
            fun fromResources(context: Context): SocialLoginConfig {
                return SocialLoginConfig(
                    googleClientId = context.getString(R.string.google_client_id),
                    facebookAppId = context.getString(R.string.facebook_app_id)
                )
            }
        }
    }

    // Facebook
    private val facebookCallbackManager: CallbackManager = CallbackManager.Factory.create()
    private val facebookLoginManager: LoginManager = LoginManager.getInstance()

    // Google One Tap
    private val oneTapClient: SignInClient = Identity.getSignInClient(activity)
    private lateinit var signInRequest: BeginSignInRequest
    private lateinit var googleSignInLauncher: ActivityResultLauncher<IntentSenderRequest>

    init {
        setupFacebookLogin()
        setupGoogleLogin()
    }

    // --- Facebook Login ---

    private fun setupFacebookLogin() {
        facebookLoginManager.registerCallback(
            facebookCallbackManager,
            object : FacebookCallback<LoginResult> {
                override fun onSuccess(result: LoginResult) {
                    val accessToken = result.accessToken
                    // Send token to YOUR BACKEND SERVER for verification
                    // The backend uses the app secret to validate - NOT the client
                    callback.onSuccess(
                        SocialLoginResult(
                            provider = SocialProvider.FACEBOOK,
                            token = accessToken.token,
                            userId = accessToken.userId,
                            email = null, // Fetched via Graph API on backend
                            displayName = null
                        )
                    )
                }

                override fun onCancel() {
                    callback.onError(SocialLoginError.Cancelled())
                }

                override fun onError(error: FacebookException) {
                    callback.onError(
                        SocialLoginError.AuthFailed(
                            error.message ?: "Facebook login failed"
                        )
                    )
                }
            }
        )
    }

    fun loginWithFacebook() {
        facebookLoginManager.logInWithReadPermissions(
            activity,
            facebookCallbackManager,
            listOf("email", "public_profile")
        )
    }

    // --- Google One Tap Sign-In ---

    private fun setupGoogleLogin() {
        // Note: Only the CLIENT ID is used on the mobile client.
        // The CLIENT SECRET is used on the BACKEND SERVER only.
        signInRequest = BeginSignInRequest.builder()
            .setGoogleIdTokenRequestOptions(
                BeginSignInRequest.GoogleIdTokenRequestOptions.builder()
                    .setSupported(true)
                    .setServerClientId(config.googleClientId) // Loaded from secure config
                    .setFilterByAuthorizedAccounts(false)
                    .build()
            )
            .setAutoSelectEnabled(true)
            .build()

        googleSignInLauncher = activity.registerForActivityResult(
            ActivityResultContracts.StartIntentSenderForResult()
        ) { result ->
            if (result.resultCode == AppCompatActivity.RESULT_OK) {
                try {
                    val credential = oneTapClient.getSignInCredentialFromIntent(result.data)
                    val idToken = credential.googleIdToken
                    if (idToken != null) {
                        // Send ID token to YOUR BACKEND SERVER for verification
                        // Backend verifies token with Google and uses client secret there
                        callback.onSuccess(
                            SocialLoginResult(
                                provider = SocialProvider.GOOGLE,
                                token = idToken,
                                userId = credential.id,
                                email = credential.id,
                                displayName = credential.displayName
                            )
                        )
                    } else {
                        callback.onError(
                            SocialLoginError.AuthFailed("No ID token received from Google")
                        )
                    }
                } catch (e: Exception) {
                    callback.onError(
                        SocialLoginError.AuthFailed(e.message ?: "Google sign-in failed")
                    )
                }
            } else {
                callback.onError(SocialLoginError.Cancelled())
            }
        }
    }

    fun loginWithGoogle() {
        oneTapClient.beginSignIn(signInRequest)
            .addOnSuccessListener(activity) { signInResult ->
                try {
                    googleSignInLauncher.launch(
                        IntentSenderRequest.Builder(signInResult.pendingIntent.intentSender)
                            .build()
                    )
                } catch (e: Exception) {
                    callback.onError(
                        SocialLoginError.AuthFailed(
                            "Could not launch Google sign-in: ${e.message}"
                        )
                    )
                }
            }
            .addOnFailureListener(activity) { e ->
                callback.onError(
                    SocialLoginError.AuthFailed(
                        "Google sign-in initialization failed: ${e.message}"
                    )
                )
            }
    }

    // --- Handle Activity Results ---

    fun handleActivityResult(requestCode: Int, resultCode: Int, data: Intent?) {
        facebookCallbackManager.onActivityResult(requestCode, resultCode, data)
    }

    // --- Sign Out ---

    fun signOut() {
        // Facebook
        facebookLoginManager.logOut()

        // Google
        oneTapClient.signOut()
            .addOnCompleteListener {
                Log.d(TAG, "Google sign-out complete")
            }
    }

    // --- Builder Pattern ---

    class Builder(private val activity: AppCompatActivity) {
        private var config: SocialLoginConfig? = null
        private var callback: SocialLoginCallback? = null

        fun withConfig(config: SocialLoginConfig) = apply { this.config = config }

        fun withCallback(callback: SocialLoginCallback) = apply { this.callback = callback }

        fun build(): SocialLoginManager {
            val resolvedConfig = config ?: SocialLoginConfig.fromBuildConfig()
            val resolvedCallback = callback
                ?: throw IllegalStateException("SocialLoginCallback must be provided")

            return SocialLoginManager(activity, resolvedConfig, resolvedCallback)
        }
    }

    companion object {
        private const val TAG = "SocialLoginManager"
    }
}


// --- TokenExchangeService.kt ---
// Tokens should be sent to your backend for verification and secret-based exchange

import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.withContext
import java.net.HttpURLConnection
import java.net.URL

class TokenExchangeService(private val backendBaseUrl: String) {

    /**
     * Send the OAuth token to your backend server.
     * The BACKEND holds the client secrets and exchanges/verifies tokens securely.
     * Mobile clients should NEVER have access to client secrets.
     */
    suspend fun exchangeToken(
        provider: SocialProvider,
        token: String
    ): Result<BackendAuthResponse> = withContext(Dispatchers.IO) {
        try {
            val url = URL("$backendBaseUrl/auth/social-login")
            val connection = url.openConnection() as HttpURLConnection
            connection.requestMethod = "POST"
            connection.setRequestProperty("Content-Type", "application/json")
            connection.doOutput = true

            val body = """
                {
                    "provider": "${provider.name.lowercase()}",
                    "token": "$token"
                }
            """.trimIndent()

            connection.outputStream.use { it.write(body.toByteArray()) }

            if (connection.responseCode == 200) {
                val response = connection.inputStream.bufferedReader().readText()
                // Parse response - use proper JSON parsing in production
                Result.success(BackendAuthResponse(sessionToken = response))
            } else {
                Result.failure(Exception("Backend auth failed: ${connection.responseCode}"))
            }
        } catch (e: Exception) {
            Result.failure(e)
        }
    }
}

data class BackendAuthResponse(
    val sessionToken: String
)


// --- Example Activity Usage ---

import android.os.Bundle
import android.widget.Button
import android.widget.Toast
import androidx.appcompat.app.AppCompatActivity
import androidx.lifecycle.lifecycleScope
import kotlinx.coroutines.launch

class LoginActivity : AppCompatActivity(), SocialLoginCallback {

    private lateinit var socialLoginManager: SocialLoginManager
    private val tokenExchangeService = TokenExchangeService(
        backendBaseUrl = BuildConfig.BACKEND_URL // Also from secure config
    )

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_login)

        // Config loaded from BuildConfig (populated by secrets-gradle-plugin)
        // or from encrypted shared preferences, or from a secure config endpoint
        socialLoginManager = SocialLoginManager.Builder(this)
            .withConfig(SocialLoginManager.SocialLoginConfig.fromBuildConfig())
            .withCallback(this)
            .build()

        findViewById<Button>(R.id.btn_facebook_login).setOnClickListener {
            socialLoginManager.loginWithFacebook()
        }

        findViewById<Button>(R.id.btn_google_login).setOnClickListener {
            socialLoginManager.loginWithGoogle()
        }
    }

    override fun onSuccess(result: SocialLoginResult) {
        // IMPORTANT: Send token to backend for secure verification
        // The backend has the client secrets and validates the token server-side
        lifecycleScope.launch {
            val exchangeResult = tokenExchangeService.exchangeToken(
                provider = result.provider,
                token = result.token
            )
            exchangeResult.onSuccess { authResponse ->
                // Store session token securely (e.g., EncryptedSharedPreferences)
                Toast.makeText(
                    this@LoginActivity,
                    "Logged in via ${result.provider}",
                    Toast.LENGTH_SHORT
                ).show()
            }.onFailure { error ->
                Toast.makeText(
                    this@LoginActivity,
                    "Backend verification failed: ${error.message}",
                    Toast.LENGTH_SHORT
                ).show()
            }
        }
    }

    override fun onError(error: SocialLoginError) {
        val message = when (error) {
            is SocialLoginError.AuthFailed -> "Auth failed: ${error.message}"
            is SocialLoginError.Cancelled -> error.message
            is SocialLoginError.ConfigError -> "Config error: ${error.message}"
        }
        Toast.makeText(this, message, Toast.LENGTH_LONG).show()
    }

    @Deprecated("Deprecated in Java")
    override fun onActivityResult(requestCode: Int, resultCode: Int, data: Intent?) {
        super.onActivityResult(requestCode, resultCode, data)
        socialLoginManager.handleActivityResult(requestCode, resultCode, data)
    }

    override fun onDestroy() {
        super.onDestroy()
        socialLoginManager.signOut()
    }
}